SELECT COUNT(1)
FROM venue


        AND type = #{type}


        AND status = #{status}


        AND (name LIKE CONCAT('%', #{keyword}, '%')
             OR code LIKE CONCAT('%', #{keyword}, '%'))

SELECT
    id, name, code, type, capacity, price, open_time, close_time, open_time_desc, description,
    status, cover_image_url, image_urls, remark, create_time, update_time
FROM venue


        AND type = #{type}


        AND status = #{status}


        AND (name LIKE CONCAT('%', #{keyword}, '%')
             OR code LIKE CONCAT('%', #{keyword}, '%'))


ORDER BY create_time DESC
LIMIT #{offset}, #{pageSize}
